105	    {
106	      options,
107	      settings,
108	      manifest: {
109	        stack: manifest.stack,
110	        packageManager: manifest.packageManager ?? "npm",
111	      },
112	      onProgress,
113	    },
114	    issues,
115	    batches,
116	  );
117	
118	  displaySummary(result);
119	  if (result.exitCode !== 0) process.exit(result.exitCode);
120	}
121	
122	function displaySummary(result: RunResult): void {
123	  const { results, logPath, config, mergedOptions } = result;
124	  if (results.length === 0) return;
125	
126	  const passed = results.filter((r) => r.success).length;
127	  const failed = results.filter((r) => !r.success).length;
128	
129	  console.log("\n" + ui.divider());
130	  console.log(colors.info("  Summary"));
131	  console.log(ui.divider());
132	  console.log(
133	    `\n  ${colors.success(`${passed} passed`)} ${colors.muted("·")} ${colors.error(`${failed} failed`)}`,
134	  );
135	  for (const r of results) {
136	    const status = r.success
137	      ? ui.statusIcon("success")
138	      : ui.statusIcon("error");
139	    const duration = r.durationSeconds
140	      ? colors.muted(` (${formatDuration(r.durationSeconds)})`)
141	      : "";
142	    const phases = r.phaseResults
143	      .map((p) => (p.success ? colors.success(p.phase) : colors.error(p.phase)))
144	      .join(" → ");
145	    const loopInfo = r.loopTriggered ? colors.warning(" [loop]") : "";
146	    const prInfo = r.prUrl ? colors.muted(` → PR #${r.prNumber}`) : "";
147	    console.log(
148	      `  ${status} #${r.issueNumber}: ${phases}${loopInfo}${prInfo}${duration}`,
149	    );
150	  }
151	  console.log("");
152	  if (logPath) {
153	    console.log(colors.muted(`  Log: ${logPath}`));
154	    console.log("");
155	  }
156	  if (mergedOptions.reflect && results.length > 0) {
157	    const reflection = analyzeRun({
158	      results,
159	      issueInfoMap: result.issueInfoMap,
160	      runLog: result.logWriter?.getRunLog() ?? null,
161	      config: { phases: config.phases, qualityLoop: config.qualityLoop },
162	    });
163	    const reflectionOutput = formatReflection(reflection);
164	    if (reflectionOutput) {
165	      console.log(reflectionOutput);
166	      console.log("");
167	    }
168	  }
169	  if (results.length > 1 && passed > 0 && !config.dryRun) {
170	    console.log(
171	      colors.muted("  Tip: Verify batch integration before merging:"),
172	    );
173	    console.log(colors.muted("     sequant merge --check"));
174	    console.log("");
175	  }
176	  if (config.dryRun) {
177	    console.log(
178	      colors.warning(
179	        "  ℹ️  This was a dry run. Use without --dry-run to execute.",
180	      ),
181	    );
182	    console.log("");
183	  }
184	}
