671	  current: number,
672	  total: number,
673	  width = 20,
674	): string {
675	  if (config.jsonMode) return "";
676	
677	  const percentage = total > 0 ? current / total : 0;
678	  const filled = Math.round(percentage * width);
679	  const empty = width - filled;
680	
681	  const filledChar = config.noColor || isLegacyWindows() ? "#" : "\u2588";
682	  const emptyChar = config.noColor || isLegacyWindows() ? "-" : "\u2591";
683	
684	  const bar = filledChar.repeat(filled) + emptyChar.repeat(empty);
685	  return config.noColor
686	    ? bar
687	    : chalk.green(filledChar.repeat(filled)) +
688	        chalk.gray(emptyChar.repeat(empty));
