22	/** Parse CLI args → validate → delegate to RunOrchestrator.run() → display summary. */
23	export async function runCommand(
24	  issues: string[],
25	  options: RunOptions,
26	): Promise<void> {
27	  console.log(ui.headerBox("SEQUANT WORKFLOW"));
28	
29	  if (!options.quiet) {
30	    try {
31	      const v = await checkVersionCached();
32	      if (v.isOutdated && v.latestVersion) {
33	        console.log(
34	          chalk.yellow(
35	            `  !  ${getVersionWarning(v.currentVersion, v.latestVersion, v.isLocalInstall)}`,
36	          ),
37	        );
38	        console.log("");
39	      }
40	    } catch {
41	      /* non-critical */
42	    }
43	  }
44	
45	  const manifest = await getManifest();
46	  if (!manifest) {
47	    console.log(
48	      chalk.red("❌ Sequant is not initialized. Run `sequant init` first."),
49	    );
50	    return;
51	  }
52	
53	  const settings = await getSettings();
54	
