  const onProgress = !options.quiet
    ? (
        issue: number,
        phase: string,
        event: "start" | "complete" | "failed",
        extra?: { durationSeconds?: number },
      ) => {
        if (event === "start")
          console.log(`  ${colors.running("▸")} #${issue}  ${phase}`);
        else if (event === "complete") {
          const dur =
            extra?.durationSeconds != null
